import { useState, useMemo, useEffect } from "react";

// --- 1. กำหนดโครงสร้างข้อมูล ---
type MenuOption = { name: string; price: number };
type MenuItem = {
  id: string;
  name: string;
  category: string;
  price: number;
  image: string;
  description?: string;
  options?: MenuOption[];
};
type CartItem = MenuItem & {
  cartItemId: string;
  quantity: number;
  selectedOptions: MenuOption[];
};
type OrderReceipt = {
  id: string;
  table: string;
  items: CartItem[];
  total: number;
  date: string;
  status: "pending" | "completed";
};

const INITIAL_MENU: MenuItem[] = [
  {
    id: "1",
    name: "ข้าวกะเพราหมูกรอบ",
    category: "Main",
    price: 65,
    image:
      "data:image/jpeg;base64,",
    description: "หมูกรอบชิ้นโต ผัดกะเพรารสจัดจ้าน",
    options: [
      { name: "เพิ่มไข่ดาว", price: 15 },
      { name: "พิเศษ", price: 20 },
    ],
  },
  {
    id: "2",
    name: "ข้าวผัดต้มยำทะเล",
    category: "Main",
    price: 80,
    image:
      "data:image/jpeg;base64,",
    description: "ข้าวผัดเครื่องต้มยำ กุ้งปลาหมึกเน้นๆ",
    options: [{ name: "เพิ่มไข่ดาว", price: 15 }],
  },
  {
    id: "3",
    name: "เฟรนช์ฟรายส์",
    category: "Snack",
    price: 49,
    image:
      "https://images.unsplash.com/photo-1576107232684-1279f390859f?w=500&q=80",
    description: "ทอดกรอบใหม่ๆ ร้อนๆ",
    options: [
      { name: "ผงชีส", price: 10 },
      { name: "ผงปาปริก้า", price: 10 },
    ],
  },
  {
    id: "4",
    name: "ไก่ทอดสไตล์เกาหลี",
    category: "Snack",
    price: 120,
    image:
      "https://images.unsplash.com/photo-1626082927389-6cd097cdc6ec?w=500&q=80",
    description: "ไก่ทอดกรอบคลุกซอสเผ็ดเกาหลี",
  },
  {
    id: "5",
    name: "ชานมไข่มุก",
    category: "Drink",
    price: 45,
    image:
      "data:image/jpeg;base64,",
    description: "ชานมไต้หวันแท้ หอมหวานละมุน",
    options: [
      { name: "หวานน้อย 50%", price: 0 },
      { name: "ไม่หวาน 0%", price: 0 },
      { name: "เพิ่มไข่มุก", price: 10 },
    ],
  },
  {
    id: "6",
    name: "น้ำแตงโมปั่น",
    category: "Drink",
    price: 50,
    image:
      "data:image/jpeg;base64,",
    description: "แตงโมสดปั่นเย็นชื่นใจ",
  },
];

const CATEGORIES = ["All", "Main", "Snack", "Drink"];
const MOCK_TABLES = Array.from({ length: 12 }, (_, i) => (i + 1).toString());

const MenuImage = ({
  src,
  alt,
  className = "",
}: {
  src: string;
  alt: string;
  className?: string;
}) => {
  const [imgError, setImgError] = useState(false);
  const isUrl = src.startsWith("http") || src.startsWith("data:image");
  if (isUrl && !imgError)
    return (
      <img
        src={src}
        alt={alt}
        className={`w-full h-full object-cover ${className}`}
        onError={() => setImgError(true)}
      />
    );
  return (
    <div
      className={`flex items-center justify-center bg-gray-100 w-full h-full ${className}`}
    >
      {imgError ? "🍽️" : src}
    </div>
  );
};

export default function App() {
  const [currentStep, setCurrentStep] = useState<
    "tables" | "menu" | "receipt" | "admin"
  >("tables");
  const [tableNumber, setTableNumber] = useState<string>("");
  const [searchQuery, setSearchQuery] = useState<string>("");
  const [selectedCategory, setSelectedCategory] = useState<string>("All");
  const [cart, setCart] = useState<CartItem[]>([]);
  const [lastOrder, setLastOrder] = useState<OrderReceipt | null>(null);
  const [isFromQR, setIsFromQR] = useState<boolean>(false);
  const [selectedMenuToAdd, setSelectedMenuToAdd] = useState<MenuItem | null>(
    null,
  );
  const [tempOptions, setTempOptions] = useState<MenuOption[]>([]);

  const [allOrders, setAllOrders] = useState<OrderReceipt[]>(() =>
    JSON.parse(localStorage.getItem("bizflow_orders") || "[]"),
  );
  const [menuItems, setMenuItems] = useState<MenuItem[]>(() =>
    JSON.parse(
      localStorage.getItem("bizflow_menu") || JSON.stringify(INITIAL_MENU),
    ),
  );

  const [adminTab, setAdminTab] = useState<"orders" | "manage_menu">("orders");
  const [editingItem, setEditingItem] = useState<MenuItem | null | "new">(null);
  const [formData, setFormData] = useState<Partial<MenuItem>>({});

  useEffect(() => {
    if (editingItem || selectedMenuToAdd)
      document.body.style.overflow = "hidden";
    else document.body.style.overflow = "unset";
  }, [editingItem, selectedMenuToAdd]);

  useEffect(() => {
    const searchParams = new URLSearchParams(window.location.search);
    if (searchParams.get("admin") === "true") setCurrentStep("admin");
    const tableFromUrl = searchParams.get("table");
    if (tableFromUrl) {
      setTableNumber(tableFromUrl);
      setIsFromQR(true);
      setCurrentStep("menu");
    }
  }, []);

  useEffect(() => {
    const handleStorageChange = () => {
      const savedOrders = localStorage.getItem("bizflow_orders");
      if (savedOrders) setAllOrders(JSON.parse(savedOrders));
      const savedMenu = localStorage.getItem("bizflow_menu");
      if (savedMenu) setMenuItems(JSON.parse(savedMenu));
    };
    window.addEventListener("storage", handleStorageChange);
    return () => window.removeEventListener("storage", handleStorageChange);
  }, []);

  const totalPrice = cart.reduce(
    (sum, item) =>
      sum +
      (item.price +
        (item.selectedOptions?.reduce((s, o) => s + o.price, 0) || 0)) *
        item.quantity,
    0,
  );
  const filteredMenu = useMemo(
    () =>
      menuItems.filter(
        (item) =>
          (selectedCategory === "All" || item.category === selectedCategory) &&
          item.name.toLowerCase().includes(searchQuery.toLowerCase()),
      ),
    [searchQuery, selectedCategory, menuItems],
  );

  // --- ฟังก์ชันฝั่งลูกค้า ---
  const handleItemClick = (item: MenuItem) => {
    if (item.options && item.options.length > 0) {
      setSelectedMenuToAdd(item);
      setTempOptions([]);
    } else {
      confirmAddToCart(item, []);
    }
  };

  // ✨ ฟังก์ชันที่หายไป กลับมาแล้วครับ!
  const toggleTempOption = (option: MenuOption) => {
    setTempOptions((prev) =>
      prev.find((o) => o.name === option.name)
        ? prev.filter((o) => o.name !== option.name)
        : [...prev, option],
    );
  };

  const confirmAddToCart = (item: MenuItem, selectedOpts: MenuOption[]) => {
    setCart((prev) => {
      const cartItemId = `${item.id}-${selectedOpts
        .map((o) => o.name)
        .sort()
        .join(",")}`;
      const existing = prev.find((c) => c.cartItemId === cartItemId);
      if (existing)
        return prev.map((c) =>
          c.cartItemId === cartItemId ? { ...c, quantity: c.quantity + 1 } : c,
        );
      return [
        ...prev,
        { ...item, cartItemId, quantity: 1, selectedOptions: selectedOpts },
      ];
    });
    setSelectedMenuToAdd(null);
  };

  const updateQuantity = (cartItemId: string, delta: number) => {
    setCart((prev) =>
      prev
        .map((c) =>
          c.cartItemId === cartItemId
            ? { ...c, quantity: c.quantity + delta }
            : c,
        )
        .filter((c) => c.quantity > 0),
    );
  };

  const handleSelectTable = (table: string) => {
    setTableNumber(table);
    window.history.pushState({}, "", `?table=${table}`);
    setCurrentStep("menu");
  };

  const handleCheckout = () => {
    const newOrder: OrderReceipt = {
      id: Date.now().toString(),
      table: tableNumber,
      items: [...cart],
      total: totalPrice,
      date: new Date().toLocaleString("th-TH"),
      status: "pending",
    };
    const updatedOrders = [...allOrders, newOrder];
    setAllOrders(updatedOrders);
    localStorage.setItem("bizflow_orders", JSON.stringify(updatedOrders));
    setLastOrder(newOrder);
    setCurrentStep("receipt");
  };

  const handleOrderMore = () => {
    setCart([]);
    setCurrentStep("menu");
  };

  const handleNewOrder = () => {
    setCart([]);
    setSearchQuery("");
    setSelectedCategory("All");
    setLastOrder(null);
    if (isFromQR) {
      setCurrentStep("menu");
    } else {
      setTableNumber("");
      window.history.pushState({}, "", window.location.pathname);
      setCurrentStep("tables");
    }
  };

  // --- ฟังก์ชันฝั่ง Admin ---
  const saveToLocalStorage = (key: string, data: any) => {
    try {
      localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
      alert(
        "❌ ไม่สามารถบันทึกข้อมูลได้: รูปภาพใหญ่เกินไป กรุณาใช้รูปลิงก์ URL หรือรูปขนาดเล็กลงครับ",
      );
    }
  };

  const handleSaveMenu = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedMenu = [...menuItems];
    const validOptions = (formData.options || []).filter(
      (o) => o.name.trim() !== "",
    );

    if (editingItem === "new") {
      updatedMenu.push({
        id: Date.now().toString(),
        name: formData.name || "เมนูใหม่",
        category: formData.category || "Main",
        price: Number(formData.price) || 0,
        image: formData.image || "🍽️",
        description: formData.description || "",
        options: validOptions,
      });
    } else if (editingItem) {
      updatedMenu = updatedMenu.map((item) =>
        item.id === editingItem.id
          ? ({ ...item, ...formData, options: validOptions } as MenuItem)
          : item,
      );
    }

    setMenuItems(updatedMenu);
    saveToLocalStorage("bizflow_menu", updatedMenu);
    setEditingItem(null);
  };

  const handleDeleteMenu = (id: string) => {
    if (confirm("🗑️ แน่ใจหรือไม่ว่าต้องการลบเมนูนี้?")) {
      const updatedMenu = menuItems.filter((item) => item.id !== id);
      setMenuItems(updatedMenu);
      saveToLocalStorage("bizflow_menu", updatedMenu);
    }
  };

  const restoreDefaultMenu = () => {
    if (confirm("ต้องการล้างข้อมูลเมนูทั้งหมดและคืนค่าเริ่มต้นใช่หรือไม่?")) {
      setMenuItems(INITIAL_MENU);
      saveToLocalStorage("bizflow_menu", INITIAL_MENU);
    }
  };

  const completeOrder = (orderId: string) => {
    const updatedOrders = allOrders.map((order) =>
      order.id === orderId ? { ...order, status: "completed" as const } : order,
    );
    setAllOrders(updatedOrders);
    saveToLocalStorage("bizflow_orders", updatedOrders);
  };

  const cancelOrder = (orderId: string) => {
    if (confirm("คุณต้องการ 'ยกเลิก' และลบบิลนี้ทิ้งใช่หรือไม่?")) {
      const updatedOrders = allOrders.filter((order) => order.id !== orderId);
      setAllOrders(updatedOrders);
      saveToLocalStorage("bizflow_orders", updatedOrders);
    }
  };

  const clearCompletedOrders = () => {
    const pendingOnly = allOrders.filter((o) => o.status === "pending");
    setAllOrders(pendingOnly);
    saveToLocalStorage("bizflow_orders", pendingOnly);
  };

  // ================= ส่วนหน้าจอ Admin Dashboard =================
  if (currentStep === "admin") {
    const pendingOrders = allOrders.filter((o) => o.status === "pending");
    return (
      <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
        <aside className="w-64 bg-gray-900 text-white flex flex-col shadow-2xl z-20 shrink-0">
          <div className="p-6 border-b border-gray-800">
            <h1 className="text-2xl font-bold text-blue-400">BizFlow</h1>
            <p className="text-xs text-gray-400 mt-1">Admin Dashboard</p>
          </div>
          <nav className="flex-1 p-4 space-y-2">
            <button
              onClick={() => setAdminTab("orders")}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition ${adminTab === "orders" ? "bg-blue-600 text-white" : "text-gray-300 hover:bg-gray-800"}`}
            >
              <span className="text-xl">🧾</span> ออเดอร์ลูกค้า{" "}
              {pendingOrders.length > 0 && (
                <span className="ml-auto bg-orange-500 text-white text-xs font-bold px-2 py-1 rounded-full">
                  {pendingOrders.length}
                </span>
              )}
            </button>
            <button
              onClick={() => setAdminTab("manage_menu")}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition ${adminTab === "manage_menu" ? "bg-blue-600 text-white" : "text-gray-300 hover:bg-gray-800"}`}
            >
              <span className="text-xl">🍔</span> จัดการเมนูอาหาร
            </button>
          </nav>
          <div className="p-4 border-t border-gray-800">
            <button
              onClick={() => {
                setCurrentStep("tables");
                window.history.pushState({}, "", window.location.pathname);
              }}
              className="text-sm text-gray-400 hover:text-white flex items-center gap-2"
            >
              <span>🏠</span> ไปหน้าจอสั่งอาหาร
            </button>
          </div>
        </aside>

        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-gray-50 pb-32">
          {adminTab === "orders" && (
            <div>
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">
                  ออเดอร์ที่กำลังสั่ง (เข้าครัว)
                </h2>
                <button
                  onClick={clearCompletedOrders}
                  className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg shadow-sm hover:bg-gray-50 transition font-medium"
                >
                  🗑️ ล้างบิลที่เสร็จแล้ว
                </button>
              </div>
              <div className="grid grid-cols-1 xl:grid-cols-2 2xl:grid-cols-3 gap-6">
                {allOrders.length === 0 && (
                  <p className="text-gray-500">ยังไม่มีออเดอร์เข้ามา...</p>
                )}
                {[...allOrders].reverse().map((order) => (
                  <div
                    key={order.id}
                    className={`bg-white rounded-2xl p-6 shadow-sm border-l-4 flex flex-col ${order.status === "pending" ? "border-orange-500" : "border-green-500 opacity-60"}`}
                  >
                    <div className="flex justify-between items-start mb-4 border-b pb-4">
                      <div>
                        <h3 className="text-2xl font-bold text-gray-900">
                          โต๊ะ {order.table}
                        </h3>
                        <p className="text-xs text-gray-500 mt-1">
                          {order.date}
                        </p>
                      </div>
                      <span
                        className={`px-3 py-1 rounded-full text-xs font-bold ${order.status === "pending" ? "bg-orange-100 text-orange-600" : "bg-green-100 text-green-600"}`}
                      >
                        {order.status === "pending"
                          ? "กำลังทำ 🍳"
                          : "เสิร์ฟแล้ว ✓"}
                      </span>
                    </div>
                    <div className="flex-1 mb-4 space-y-3">
                      {order.items.map((item) => (
                        <div
                          key={item.cartItemId}
                          className="flex justify-between text-sm"
                        >
                          <div>
                            <span className="font-bold">
                              {item.quantity}x {item.name}
                            </span>
                            {item.selectedOptions &&
                              item.selectedOptions.length > 0 && (
                                <p className="text-xs text-orange-500 mt-0.5">
                                  {item.selectedOptions
                                    .map((o) => o.name)
                                    .join(", ")}
                                </p>
                              )}
                          </div>
                          <span className="text-gray-500 font-medium">
                            ฿
                            {(item.price +
                              (item.selectedOptions?.reduce(
                                (s, o) => s + o.price,
                                0,
                              ) || 0)) *
                              item.quantity}
                          </span>
                        </div>
                      ))}
                    </div>
                    {order.status === "pending" && (
                      <div className="mt-4 flex gap-2 w-full pt-4 border-t">
                        <button
                          onClick={() => cancelOrder(order.id)}
                          className="flex-1 bg-red-50 hover:bg-red-100 text-red-600 font-bold py-2.5 rounded-xl transition"
                        >
                          ยกเลิกบิล
                        </button>
                        <button
                          onClick={() => completeOrder(order.id)}
                          className="flex-[2] bg-green-500 hover:bg-green-600 text-white font-bold py-2.5 rounded-xl transition"
                        >
                          เสิร์ฟแล้ว ✓
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {adminTab === "manage_menu" && (
            <div className="bg-white rounded-2xl shadow-sm border overflow-hidden">
              <div className="p-6 border-b flex justify-between items-center bg-gray-50 sticky top-0 z-10">
                <h2 className="text-xl font-bold text-gray-800">
                  จัดการรายการอาหาร
                </h2>
                <div className="flex gap-3">
                  <button
                    onClick={restoreDefaultMenu}
                    className="bg-gray-200 text-gray-700 px-4 py-2 rounded-lg font-bold text-sm"
                  >
                    🔄 คืนค่าระบบ
                  </button>
                  <button
                    onClick={() => {
                      setEditingItem("new");
                      setFormData({ category: "Main", image: "", options: [] });
                    }}
                    className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold"
                  >
                    + เพิ่มเมนู
                  </button>
                </div>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[600px]">
                  <thead className="bg-gray-50 text-gray-500 text-xs uppercase font-bold">
                    <tr>
                      <th className="p-4 w-24">รูป</th>
                      <th className="p-4">ชื่อเมนู</th>
                      <th className="p-4">ราคา</th>
                      <th className="p-4 text-center">จัดการ</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {menuItems.map((item) => (
                      <tr key={item.id} className="hover:bg-gray-50 transition">
                        <td className="p-4 w-24">
                          <div className="w-16 h-16 rounded-xl overflow-hidden bg-gray-100 border border-gray-100 shadow-sm">
                            <MenuImage
                              src={item.image}
                              alt={item.name}
                              className="text-2xl"
                            />
                          </div>
                        </td>
                        <td className="p-4">
                          <p className="font-bold text-gray-900">{item.name}</p>
                          <p className="text-xs text-gray-400">
                            {item.category}
                          </p>
                        </td>
                        <td className="p-4 font-bold text-blue-600">
                          ฿{item.price}
                        </td>
                        <td className="p-4">
                          <div className="flex justify-center gap-2">
                            <button
                              onClick={() => {
                                setEditingItem(item);
                                setFormData({
                                  ...item,
                                  options: item.options
                                    ? [...item.options]
                                    : [],
                                });
                              }}
                              className="bg-yellow-50 text-yellow-600 font-bold px-4 py-2 rounded-xl border border-yellow-100 hover:bg-yellow-100 transition"
                            >
                              แก้ไข
                            </button>
                            <button
                              onClick={() => handleDeleteMenu(item.id)}
                              className="bg-red-50 text-red-600 font-bold px-4 py-2 rounded-xl border border-red-100 hover:bg-red-100 transition"
                            >
                              ลบ
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {editingItem && (
            <div className="fixed inset-0 bg-white z-[100] flex flex-col overflow-hidden animate-in fade-in duration-200">
              <header className="h-20 border-b flex items-center justify-between px-6 md:px-12 bg-gray-900 text-white shrink-0">
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => setEditingItem(null)}
                    className="hover:bg-white/10 p-2 rounded-full transition text-3xl leading-none"
                  >
                    &times;
                  </button>
                  <h2 className="text-xl md:text-2xl font-bold">
                    {editingItem === "new" ? "✨ เมนูใหม่" : "📝 แก้ไขเมนู"}
                  </h2>
                </div>
                <div className="flex gap-3">
                  <button
                    onClick={() => setEditingItem(null)}
                    className="hidden md:block px-6 py-2 rounded-xl border border-gray-600 text-gray-300 font-bold"
                  >
                    ยกเลิก
                  </button>
                  <button
                    onClick={handleSaveMenu}
                    className="px-8 py-2.5 rounded-xl bg-blue-600 hover:bg-blue-700 shadow-lg font-bold"
                  >
                    บันทึกข้อมูล
                  </button>
                </div>
              </header>

              <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
                <div className="w-full md:w-2/5 bg-gray-50 border-r flex flex-col p-6 md:p-12 items-center justify-center shrink-0">
                  <div className="w-full max-w-[320px] aspect-square rounded-3xl overflow-hidden shadow-2xl bg-white border-8 border-white ring-1 ring-gray-200 mb-6">
                    <MenuImage
                      src={formData.image || ""}
                      alt="Preview"
                      className="text-8xl"
                    />
                  </div>
                  <div className="w-full max-w-[320px] space-y-3">
                    <label className="block w-full text-center bg-blue-600 text-white py-3 rounded-2xl cursor-pointer hover:bg-blue-700 transition font-bold shadow-md">
                      📁 เลือกรูปภาพจากเครื่อง
                      <input
                        type="file"
                        accept="image/*"
                        className="hidden"
                        onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file) {
                            if (file.size > 2 * 1024 * 1024)
                              return alert("รูปใหญ่เกิน 2MB ครับ");
                            const reader = new FileReader();
                            reader.onloadend = () =>
                              setFormData({
                                ...formData,
                                image: reader.result as string,
                              });
                            reader.readAsDataURL(file);
                          }
                        }}
                      />
                    </label>
                    <input
                      type="text"
                      placeholder="หรือวางลิงก์ URL รูปภาพ"
                      value={formData.image || ""}
                      onChange={(e) =>
                        setFormData({ ...formData, image: e.target.value })
                      }
                      className="w-full bg-white border border-gray-300 rounded-xl p-3 text-center text-sm shadow-sm outline-none focus:border-blue-500"
                    />
                  </div>
                </div>

                <div className="flex-1 bg-white p-6 md:p-12 overflow-y-auto">
                  <div className="max-w-2xl mx-auto space-y-8 pb-32">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest">
                          ชื่ออาหาร
                        </label>
                        <input
                          type="text"
                          required
                          value={formData.name || ""}
                          onChange={(e) =>
                            setFormData({ ...formData, name: e.target.value })
                          }
                          className="w-full border-2 border-gray-100 bg-gray-50 rounded-2xl p-4 text-lg font-bold focus:bg-white focus:border-blue-500 transition-all outline-none"
                        />
                      </div>
                      <div>
                        <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest">
                          ราคา (฿)
                        </label>
                        <input
                          type="number"
                          required
                          value={formData.price ?? ""}
                          onChange={(e) =>
                            setFormData({
                              ...formData,
                              price: Number(e.target.value),
                            })
                          }
                          className="w-full border-2 border-gray-100 bg-gray-50 rounded-2xl p-4 text-lg font-bold focus:bg-white focus:border-blue-500 transition-all outline-none text-blue-600"
                        />
                      </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest">
                          หมวดหมู่
                        </label>
                        <select
                          value={formData.category || "Main"}
                          onChange={(e) =>
                            setFormData({
                              ...formData,
                              category: e.target.value,
                            })
                          }
                          className="w-full border-2 border-gray-100 bg-gray-50 rounded-2xl p-4 font-bold focus:bg-white focus:border-blue-500 outline-none"
                        >
                          {CATEGORIES.filter((c) => c !== "All").map((c) => (
                            <option key={c} value={c}>
                              {c}
                            </option>
                          ))}
                        </select>
                      </div>
                      <div>
                        <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest">
                          คำบรรยาย
                        </label>
                        <input
                          type="text"
                          value={formData.description || ""}
                          onChange={(e) =>
                            setFormData({
                              ...formData,
                              description: e.target.value,
                            })
                          }
                          className="w-full border-2 border-gray-100 bg-gray-50 rounded-2xl p-4 font-medium focus:bg-white focus:border-blue-500 outline-none"
                        />
                      </div>
                    </div>
                    <div className="border-t-2 border-gray-50 pt-8">
                      <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-bold text-gray-800">
                          ➕ ตัวเลือกเสริม (Add-ons)
                        </h3>
                        <button
                          type="button"
                          onClick={() =>
                            setFormData({
                              ...formData,
                              options: [
                                ...(formData.options || []),
                                { name: "", price: 0 },
                              ],
                            })
                          }
                          className="bg-blue-50 text-blue-600 px-4 py-2 rounded-xl font-bold hover:bg-blue-100 transition border border-blue-100"
                        >
                          + เพิ่ม
                        </button>
                      </div>
                      <div className="space-y-3">
                        {formData.options?.map((opt, idx) => (
                          <div
                            key={idx}
                            className="flex gap-3 items-center bg-gray-50 p-3 rounded-2xl border-2 border-transparent hover:border-gray-200 transition-all"
                          >
                            <input
                              type="text"
                              placeholder="ชื่อ (เช่น เพิ่มไข่ดาว)"
                              value={opt.name}
                              onChange={(e) => {
                                const opts = [...(formData.options || [])];
                                opts[idx].name = e.target.value;
                                setFormData({ ...formData, options: opts });
                              }}
                              className="flex-1 bg-transparent p-2 border-b border-gray-300 outline-none focus:border-blue-500 font-bold"
                            />
                            <div className="w-24 flex items-center gap-1">
                              <span className="text-gray-400">+</span>
                              <input
                                type="number"
                                value={opt.price}
                                onChange={(e) => {
                                  const opts = [...(formData.options || [])];
                                  opts[idx].price = Number(e.target.value);
                                  setFormData({ ...formData, options: opts });
                                }}
                                className="w-full bg-transparent p-2 border-b border-gray-300 outline-none focus:border-blue-500 font-bold text-blue-600"
                              />
                            </div>
                            <button
                              type="button"
                              onClick={() =>
                                setFormData({
                                  ...formData,
                                  options: (formData.options || []).filter(
                                    (_, i) => i !== idx,
                                  ),
                                })
                              }
                              className="text-red-500 text-2xl px-2"
                            >
                              &times;
                            </button>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  // ================= ส่วนลูกค้า =================
  if (currentStep === "tables") {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6 font-sans">
        <div className="max-w-3xl w-full">
          <div className="text-center mb-8">
            <h1 className="text-3xl md:text-4xl font-bold text-blue-600 mb-3">
              BizFlow
            </h1>
            <h2 className="text-xl text-gray-600">กรุณาเลือกโต๊ะของคุณ</h2>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {MOCK_TABLES.map((table) => (
              <button
                key={table}
                onClick={() => handleSelectTable(table)}
                className="bg-white border-2 border-transparent hover:border-blue-500 hover:shadow-lg text-gray-800 rounded-2xl p-6 flex flex-col items-center justify-center transition-all active:scale-95"
              >
                <div className="text-4xl mb-2 text-gray-400">🍽️</div>
                <div className="text-xl font-bold">โต๊ะ {table}</div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (currentStep === "receipt" && lastOrder) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 md:p-6 font-sans">
        <div className="bg-white max-w-md w-full rounded-2xl shadow-xl overflow-hidden print:shadow-none print:w-full">
          <div className="bg-blue-600 text-white text-center p-6 print:bg-transparent print:text-black print:p-2">
            <div className="w-16 h-16 bg-white text-blue-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-3 border-2 border-blue-600 print:border-black print:text-black">
              ✓
            </div>
            <h1 className="text-2xl font-bold mb-1">สั่งอาหารสำเร็จ</h1>
            <p className="text-blue-100 print:text-gray-600">
              ออเดอร์ถูกส่งเข้าครัวแล้ว
            </p>
          </div>
          <div className="p-6 md:p-8">
            <div className="flex justify-between items-center mb-6 text-gray-600 border-b border-dashed border-gray-300 pb-4">
              <div>
                <p className="text-sm">โต๊ะ</p>
                <p className="text-xl font-bold text-gray-900">
                  {lastOrder.table}
                </p>
              </div>
              <div className="text-right">
                <p className="text-sm">วันที่ทำรายการ</p>
                <p className="font-medium text-gray-800 text-sm">
                  {lastOrder.date}
                </p>
              </div>
            </div>
            <div className="space-y-4 mb-6">
              {lastOrder.items.map((item) => (
                <div
                  key={item.cartItemId}
                  className="flex justify-between items-start"
                >
                  <div className="flex-1 pr-4">
                    <p className="font-bold text-gray-800">{item.name}</p>
                    {item.selectedOptions &&
                      item.selectedOptions.length > 0 && (
                        <p className="text-xs text-orange-600 mt-0.5">
                          {item.selectedOptions.map((o) => o.name).join(", ")}
                        </p>
                      )}
                    <p className="text-sm text-gray-500 mt-1">
                      ฿
                      {item.price +
                        (item.selectedOptions?.reduce(
                          (s, o) => s + o.price,
                          0,
                        ) || 0)}{" "}
                      x {item.quantity}
                    </p>
                  </div>
                  <p className="font-bold text-gray-800">
                    ฿
                    {(item.price +
                      (item.selectedOptions?.reduce((s, o) => s + o.price, 0) ||
                        0)) *
                      item.quantity}
                  </p>
                </div>
              ))}
            </div>
            <div className="border-t border-gray-200 pt-4 flex justify-between items-end mb-8 print:mb-0">
              <span className="text-lg font-bold text-gray-700">ยอดรวม</span>
              <span className="text-3xl font-bold text-blue-600 print:text-black">
                ฿{lastOrder.total}
              </span>
            </div>
            <div className="space-y-3 print:hidden">
              <button
                onClick={() => window.print()}
                className="w-full bg-blue-50 text-blue-600 font-bold py-3 rounded-xl hover:bg-blue-100 transition flex justify-center items-center gap-2"
              >
                📥 บันทึกบิล / พิมพ์
              </button>
              <button
                onClick={handleOrderMore}
                className="w-full bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition"
              >
                + สั่งอาหารเพิ่ม (โต๊ะเดิม)
              </button>
              <button
                onClick={handleNewOrder}
                className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition"
              >
                ดูเมนูหลัก
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 flex flex-col md:flex-row font-sans relative">
      <div className="flex-1 p-4 md:p-6 w-full">
        <div className="bg-white p-4 rounded-xl shadow-sm mb-6 flex flex-col sm:flex-row justify-between items-center gap-4">
          <h1 className="text-2xl font-bold text-gray-900">
            BizFlow - สั่งอาหาร
          </h1>
          <div className="flex items-center gap-3 bg-gray-50 px-4 py-2 rounded-lg border border-gray-200">
            <span className="text-2xl">🍽️</span>
            <div>
              <p className="text-xs text-gray-500 font-medium">โต๊ะที่เลือก</p>
              <p className="font-bold text-blue-600 text-lg leading-tight">
                {tableNumber}
              </p>
            </div>
            {!isFromQR && (
              <button
                onClick={() => {
                  setCurrentStep("tables");
                  setTableNumber("");
                  window.history.pushState({}, "", window.location.pathname);
                }}
                className="ml-2 text-sm text-gray-400 hover:text-blue-600 underline"
              >
                เปลี่ยน
              </button>
            )}
          </div>
        </div>
        <div className="mb-6 space-y-4">
          <input
            type="text"
            placeholder="🔍 ค้นหาเมนู..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full border border-gray-300 rounded-lg px-4 py-3 outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition shadow-sm"
          />
          <div className="flex gap-2 overflow-x-auto pb-2">
            {CATEGORIES.map((cat) => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`whitespace-nowrap px-4 py-2 rounded-full font-medium transition ${selectedCategory === cat ? "bg-blue-600 text-white shadow-md" : "bg-white text-gray-600 border border-gray-200 hover:bg-gray-100"}`}
              >
                {cat === "All" ? "ทั้งหมด" : cat}
              </button>
            ))}
          </div>
        </div>
        <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {filteredMenu.map((item) => (
            <div
              key={item.id}
              className="bg-white rounded-2xl shadow-sm hover:shadow-md transition flex flex-col overflow-hidden border border-gray-100"
            >
              <div className="h-40 w-full bg-gray-100">
                <MenuImage
                  src={item.image}
                  alt={item.name}
                  className="text-6xl"
                />
              </div>
              <div className="p-4 flex flex-col flex-1">
                <h3 className="font-semibold text-lg leading-tight line-clamp-1">
                  {item.name}
                </h3>
                {item.description && (
                  <p className="text-xs text-gray-500 mt-1 line-clamp-2">
                    {item.description}
                  </p>
                )}
                <div className="mt-auto pt-3">
                  <p className="text-blue-600 font-bold mb-3 text-lg">
                    ฿{item.price}
                  </p>
                  <button
                    onClick={() => handleItemClick(item)}
                    className="w-full bg-blue-50 text-blue-600 font-bold py-2 rounded-lg hover:bg-blue-600 hover:text-white transition active:scale-95"
                  >
                    + เพิ่ม
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="w-full md:w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl md:shadow-none z-10 sticky bottom-0 md:h-screen md:top-0 shrink-0">
        <div className="p-4 md:p-6 border-b border-gray-100 flex justify-between items-center bg-white">
          <h2 className="text-xl font-bold text-gray-800">ตะกร้าของคุณ</h2>
          <span className="bg-blue-600 text-white text-sm px-3 py-1 rounded-full font-bold">
            {cart.reduce((sum, item) => sum + item.quantity, 0)} รายการ
          </span>
        </div>
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-3 max-h-[35vh] md:max-h-full bg-gray-50 md:bg-white">
          {cart.length === 0 ? (
            <div className="text-center text-gray-400 mt-10">
              ยังไม่มีรายการอาหาร
            </div>
          ) : (
            cart.map((item) => (
              <div
                key={item.cartItemId}
                className="bg-white md:bg-gray-50 p-3 rounded-xl shadow-sm border border-gray-100"
              >
                <div className="flex justify-between items-start mb-2">
                  <div className="flex-1 pr-2">
                    <p className="font-bold leading-tight">{item.name}</p>
                    {item.selectedOptions &&
                      item.selectedOptions.length > 0 && (
                        <p className="text-xs text-orange-500 mt-1">
                          {item.selectedOptions.map((o) => o.name).join(", ")}
                        </p>
                      )}
                    <p className="text-sm text-blue-600 font-bold mt-1">
                      ฿
                      {item.price +
                        (item.selectedOptions?.reduce(
                          (s, o) => s + o.price,
                          0,
                        ) || 0)}
                    </p>
                  </div>
                </div>
                <div className="flex items-center justify-end gap-2 border-t border-gray-100 pt-2">
                  <button
                    onClick={() => updateQuantity(item.cartItemId, -1)}
                    className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded-full text-gray-600 hover:bg-gray-100 active:bg-gray-200 font-bold"
                  >
                    -
                  </button>
                  <span className="w-6 text-center font-bold text-sm">
                    {item.quantity}
                  </span>
                  <button
                    onClick={() => updateQuantity(item.cartItemId, 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded-full text-gray-600 hover:bg-gray-100 active:bg-gray-200 font-bold"
                  >
                    +
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
        <div className="p-4 md:p-6 border-t border-gray-100 bg-white">
          <div className="flex justify-between mb-4 text-xl font-bold">
            <span className="text-gray-700">รวมทั้งหมด</span>
            <span className="text-blue-600">฿{totalPrice}</span>
          </div>
          <button
            onClick={handleCheckout}
            disabled={cart.length === 0}
            className={`w-full py-4 rounded-xl font-bold text-white text-lg transition-all ${cart.length === 0 ? "bg-gray-300 cursor-not-allowed" : "bg-blue-600 hover:bg-blue-700 shadow-lg active:scale-[0.98]"}`}
          >
            ยืนยันการสั่งอาหาร
          </button>
        </div>
      </div>

      {/* Modal ตัวเลือกเสริม ฝั่งลูกค้า */}
      {selectedMenuToAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 z-[110]">
          <div className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="h-48 w-full bg-gray-100 relative">
              <MenuImage
                src={selectedMenuToAdd.image}
                alt={selectedMenuToAdd.name}
                className="text-6xl"
              />
              <button
                onClick={() => setSelectedMenuToAdd(null)}
                className="absolute top-4 right-4 bg-white/80 backdrop-blur text-gray-800 w-8 h-8 rounded-full font-bold shadow hover:bg-white"
              >
                &times;
              </button>
            </div>
            <div className="p-6">
              <h3 className="text-2xl font-bold text-gray-900 mb-1">
                {selectedMenuToAdd.name}
              </h3>
              <p className="text-blue-600 font-bold text-lg mb-4">
                ฿{selectedMenuToAdd.price}
              </p>
              <div className="mb-6">
                <p className="font-bold text-gray-800 mb-3 border-b pb-2">
                  เลือกเพิ่มเติม
                </p>
                <div className="space-y-3">
                  {selectedMenuToAdd.options?.map((opt, idx) => {
                    const isSelected = tempOptions.some(
                      (o) => o.name === opt.name,
                    );
                    return (
                      <label
                        key={idx}
                        className={`flex items-center justify-between p-3 border rounded-xl cursor-pointer transition ${isSelected ? "border-blue-500 bg-blue-50" : "border-gray-200 hover:bg-gray-50"}`}
                      >
                        <div className="flex items-center gap-3">
                          <input
                            type="checkbox"
                            checked={isSelected}
                            onChange={() => toggleTempOption(opt)}
                            className="w-5 h-5 text-blue-600 rounded"
                          />
                          <span>{opt.name}</span>
                        </div>
                        <span className="text-gray-500">+{opt.price} ฿</span>
                      </label>
                    );
                  })}
                </div>
              </div>
              <button
                onClick={() => confirmAddToCart(selectedMenuToAdd, tempOptions)}
                className="w-full bg-blue-600 text-white font-bold py-3.5 rounded-xl hover:bg-blue-700 transition"
              >
                เพิ่มลงตะกร้า (฿
                {selectedMenuToAdd.price +
                  tempOptions.reduce((s, o) => s + o.price, 0)}
                )
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
